head.script:
scwin.onpageload = function () {
    scwin._load();
};

scwin._getParam = function () {
    try { return $p.getParameter("paramData") || {}; } catch (e) { return {}; }
};

scwin._callApi = function (method, url, callback) {
    var xhr = new XMLHttpRequest();
    xhr.open(method, url, true);
    xhr.onreadystatechange = function () {
        if (xhr.readyState === 4) {
            if (xhr.status >= 200 && xhr.status < 300) {
                try {
                    callback(JSON.parse(xhr.responseText || "{}"));
                } catch (e) {
                    callback({});
                }
            } else {
                callback(null);
            }
        }
    };
    xhr.send(method === "POST" ? "" : null);
};

scwin._suggestNextVerNo = function (latestVer) {
    var v = (latestVer || "").trim();
    if (!v) { return "v1.0"; }
    var m = v.match(/^(v?)(\d+)\.(\d+)$/i);
    if (m) {
        var major = parseInt(m[2], 10);
        var minor = parseInt(m[3], 10) + 1;
        return (m[1] === "V" ? "V" : "v") + major + "." + minor;
    }
    return v + ".1";
};

scwin._load = function () {
    var p = scwin._getParam();
    var assetId = p.assetId;
    if (!assetId) { return; }

    scwin._callApi("GET", "/api/dam/assets/" + encodeURIComponent(assetId), function (res) {
        if (!res || !res.asset) { return; }
        var a = res.asset;
        var versions = res.versions || [];
        var latest = versions.length > 0 ? versions[0] : null;
        var latestVer = latest ? latest.verNo : "";
        var preview = (latest && latest.previewUrl) ? latest.previewUrl : (a.previewUrl || "/cm/dam/images/preview/document.svg");

        dmPopup.set("ASSET_ID", String(a.assetId != null ? a.assetId : ""));
        dmPopup.set("FILE_NM", a.fileNm || "");
        dmPopup.set("NEW_VER_NO", scwin._suggestNextVerNo(latestVer));
        dmPopup.set("UPLOAD_FILE_NM", "");
        var owners = ["Carol", "David", "Alice", "Bob", "SYSTEM"];
        var ownerVal = a.ownerNm || "Carol";
        if (owners.indexOf(ownerVal) < 0) { ownerVal = "Carol"; }
        dmPopup.set("CONTRIBUTORS", ownerVal);
        dmPopup.set("CHANGE_NOTES", (latest && latest.changeLog) ? latest.changeLog : "");
        dmPopup.set("PREVIEW_URL", preview);

        try {
            var t = $p.getComponentById("txt_fb_popup_title");
            if (t && typeof t.setLabel === "function") {
                t.setLabel("Upload New Version: " + (a.fileNm || ""));
            }
        } catch (e) {}

        try {
            var img = $p.getComponentById("img_fb_popup_preview");
            if (img && typeof img.setSrc === "function") {
                img.setSrc(dmPopup.get("PREVIEW_URL"));
            }
        } catch (e) {}
    });
};

scwin.btn_fb_browse_onclick = function () {
    dmPopup.set("UPLOAD_FILE_NM", dmPopup.get("FILE_NM") || "");
};

scwin.btn_fb_cancel_onclick = function () {
    try {
        if (typeof $p.closePopup === "function") { $p.closePopup(); }
    } catch (e) {}
};

scwin.btn_fb_submit_onclick = function () {
    alert("Demo: chưa có API lưu phiên bản. Gửi sẽ gồm VER_NO=" + (dmPopup.get("NEW_VER_NO") || "") + ", Contributors=" + (dmPopup.get("CONTRIBUTORS") || "") + ".");
    scwin.btn_fb_cancel_onclick();
};
